# Benchmark taxonomy with per-model scores
import json

BENCHMARKS = {
    "knowledge": {
        "mmlu": {"gpt4o": 88.7, "claude_3.5": 88.3, "llama3_405b": 87.9, "saturation": 89},
        "arc_challenge": {"gpt4o": 95.2, "claude_3.5": 94.8, "llama3_405b": 93.5, "saturation": 96},
    },
    "reasoning": {
        "gsm8k": {"gpt4o": 96.4, "claude_3.5": 95.0, "llama3_405b": 94.8, "saturation": 97},
        "math": {"gpt4o": 76.2, "claude_3.5": 71.5, "llama3_405b": 68.3, "saturation": 80},
    },
    "code": {
        "humaneval": {"gpt4o": 92.0, "claude_3.5": 90.2, "llama3_405b": 89.0, "saturation": 93},
        "swe_bench": {"gpt4o": 31.0, "claude_3.5": 49.0, "llama3_405b": 24.5, "saturation": 60},
    },
    "safety": {
        "truthfulqa": {"gpt4o": 74.4, "claude_3.5": 73.0, "llama3_405b": 72.1, "saturation": 76},
    }
}

def headroom_report(benchmarks, model="claude_3.5"):
    """Identify which benchmarks still differentiate models."""
    for cat, bench_dict in benchmarks.items():
        for name, scores in bench_dict.items():
            gap = scores["saturation"] - scores[model]
            print(f"{name:20s} {model}={scores[model]:.1f}  headroom={gap:.1f}pt  "
                  f"high_value={'YES' if gap > 10 else 'NO'}")

headroom_report(BENCHMARKS)
